#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int steps = 0;
    while (N > 1) {
        steps++;
        int instructions = 0;
        for (int i = 1; i < N; i += 2) {
            instructions++;
            printf("%d+%d=%d ", i - 1, i, i);
        }
        printf("\n");
        N /= 2;
    }
    printf("%d\n", steps);
    return 0;
}

