code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int steps = 0;
        while (N > 1) {
            steps++;
            int instructions = 0;
            for (int i = 1; i < N; i += 2) {
                instructions++;
                System.out.print(i - 1 + "+" + i + "=" + i + " ");
            }
            System.out.println();
            N /= 2;
        }
        System.out.println(steps);
    }
}

